import{_ as t,o as l,c as i,ag as r}from"./chunks/framework.CNG7EpJN.js";const u=JSON.parse('{"title":"セルフオーダー画面","description":"","frontmatter":{"title":"セルフオーダー画面"},"headers":[],"relativePath":"tenant/17-customer.md","filePath":"tenant/17-customer.md"}'),e={name:"tenant/17-customer.md"};function o(n,a,s,d,h,c){return l(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="_17-セルフオーダー画面" tabindex="-1">17. セルフオーダー画面 <a class="header-anchor" href="#_17-セルフオーダー画面" aria-label="Permalink to &quot;17. セルフオーダー画面&quot;">​</a></h1><p>セルフオーダー画面は、お客様がテーブルQRコードから開く注文画面です。店舗スタッフは、表示内容と注文の流れを理解しておくと問い合わせ対応がしやすくなります。</p><h2 id="お客様の注文手順" tabindex="-1">お客様の注文手順 <a class="header-anchor" href="#お客様の注文手順" aria-label="Permalink to &quot;お客様の注文手順&quot;">​</a></h2><ol><li>テーブルのQRコードをスマートフォンで読み取ります。</li><li>検索、カテゴリ、クイック絞り込みからメニューを選び、数量やオプションを選択してカートに入れます。</li><li>カート内容を確認します。</li><li><strong>ゲスト名（任意）</strong>: 注文送信前に、注文者の名前（ニックネーム等）を入力できます。入力すると、注文履歴やレジ画面で誰の注文かが判別しやすくなります。</li><li>送信前の確認で、品切れ、上限、アレルギー情報、提供時間が長い品目を確認します。</li><li>注文を送信します。</li><li>必要に応じてスタッフ呼び出しやAIウェイターを利用します。</li></ol><h2 id="メニューを探しやすくする表示" tabindex="-1">メニューを探しやすくする表示 <a class="header-anchor" href="#メニューを探しやすくする表示" aria-label="Permalink to &quot;メニューを探しやすくする表示&quot;">​</a></h2><p>セルフオーダー画面には、お客様が迷わず選べるように以下の導線があります。</p><ul><li><strong>検索</strong>: メニュー名、説明、カテゴリ名で検索できます。</li><li><strong>クイック絞り込み</strong>: 人気、早く出る、辛い、アレルギー、ベジ、子ども向けで絞り込めます。</li><li><strong>アレルギー除外</strong>: 卵、乳、小麦、えび、かに、そば、落花生を選ぶと、それらを含む品目を一覧から除外します。</li><li><strong>スタッフ確認導線</strong>: アレルギー絞り込み中は「スタッフに確認する」ボタンを表示します。押すとスタッフ呼び出しに「アレルギー確認をお願いします」という理由で通知します。</li><li><strong>待ち時間目安</strong>: 店舗全体の直近平均待ち時間がある場合は検索欄の下に表示します。品目カードの「約X分」は、店舗が提供目安分を設定している場合はその値を優先し、未設定の場合は過去30日の完成/提供実績が2件以上ある品目だけ表示します。</li></ul><p>クイック絞り込みは、店舗が登録した「辛さ」「早く出る」「ベジ」「子ども向け」「提供目安分」を優先します。未設定の品目は、品名・説明文・カテゴリ名・過去実績から補助判定します。AIによる曖昧判定ではありません。</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>アレルギー情報は店舗で登録したメニュー情報をもとに表示します。最終確認が必要な場合は、必ず店舗スタッフが確認してください。</p></div><h2 id="オプション選択" tabindex="-1">オプション選択 <a class="header-anchor" href="#オプション選択" aria-label="Permalink to &quot;オプション選択&quot;">​</a></h2><p>オプションがある商品を選ぶと、オプション選択モーダルを表示します。</p><ul><li>必須オプションは「必須」と表示し、必要数を選ぶまでカート追加ボタンを無効にします。</li><li>任意オプションは「任意」と表示します。</li><li>複数選択では、選択済み数と選択上限を表示します。上限に達すると追加選択できません。</li><li>価格差は、追加料金、値引き、価格差なしを表示します。</li><li>売り切れ/提供不可のオプションは「売り切れ」と表示し、選択できない状態にします。</li></ul><p>お客様が画面を開いた後にオプション提供可否が変わった場合でも、注文送信時にサーバー側で再検証します。選択できないオプションが含まれる場合は送信できません。</p><h2 id="品切れ時の代替提案" tabindex="-1">品切れ時の代替提案 <a class="header-anchor" href="#品切れ時の代替提案" aria-label="Permalink to &quot;品切れ時の代替提案&quot;">​</a></h2><p>品切れになった商品はメニュー一覧から非表示になります。お客様のカートに入っていた商品が途中で品切れになった場合は、その商品をカートから外し、「こちらなら提供できます」として注文可能な代替候補を表示します。</p><p>候補は、店舗側で手動設定した「品切れ時の代替提案」を最優先します。手動設定がない場合は、同じカテゴリ、今日のおすすめ、店舗全体の人気、早く出る品目を優先して表示します。売り切れ品そのものは一覧に残しません。</p><h2 id="追加注文の導線" tabindex="-1">追加注文の導線 <a class="header-anchor" href="#追加注文の導線" aria-label="Permalink to &quot;追加注文の導線&quot;">​</a></h2><p>同じテーブルセッションで注文履歴がある場合、以下の2つの追加注文導線を表示します。</p><ul><li><strong>前回のご注文</strong>: 同じ品目をワンタップで再注文できます。品切れ品は追加できません。</li><li><strong>もう一品いかがですか</strong>: この卓だけの傾向ではなく、店舗全体のおすすめ・人気から候補を表示します。</li><li><strong>この料理に合う一品</strong>: カートに追加した料理に対して、過去の注文実績で一緒に注文されることが多い品目を表示します。</li></ul><p>「この料理に合う一品」はAI生成ではありません。<code>order_items</code> の過去60日実績から、同じ注文内に一緒に含まれた品目ペアを集計し、一定件数以上ある組み合わせだけを表示します。実績が少ない店舗、開店直後、品目名が頻繁に変わる店舗では表示されないことがあります。</p><p>この設計により、スタッフがお客様へ説明する場合も「前回と同じもの」「お店全体でよく出ているもの」「一緒に頼まれやすいもの」の3種類で説明できます。</p><h2 id="注文送信前の最終確認" tabindex="-1">注文送信前の最終確認 <a class="header-anchor" href="#注文送信前の最終確認" aria-label="Permalink to &quot;注文送信前の最終確認&quot;">​</a></h2><p>カートモーダルには「送信前の確認」を表示します。</p><p>送信を止める項目:</p><ul><li>ラストオーダー終了</li><li>カート内の商品が品切れ、またはメニューから消えている</li><li>選択済みオプションが提供不可になっている</li><li>1回の注文上限品数を超えている</li><li>1回の注文上限金額を超えている</li></ul><p>注意として表示する項目:</p><ul><li>アレルギー情報が選択されている</li><li>アレルギー除外フィルタを使っている</li><li>提供目安が長めの品目が入っている</li></ul><p>注意項目は注文を止めません。お客様に気づいてもらうための表示です。アレルギーはセルフ判断だけで完結させず、必要に応じてスタッフ確認につなげてください。</p><h2 id="多言語表示" tabindex="-1">多言語表示 <a class="header-anchor" href="#多言語表示" aria-label="Permalink to &quot;多言語表示&quot;">​</a></h2><p>セルフオーダー画面のボタン、検索欄、絞り込み、代替提案、追加提案などの文言は翻訳データで表示します。メニュー名、カテゴリ名、説明文、オプション名はメニュー翻訳データを使います。</p><p>2026-04-29時点の画面では、日本語、英語、簡体中文、韓国語を選択できます。繁体字は翻訳データとして保存できますが、現在のセルフメニュー画面では表示選択肢に出さず、簡体中文にフォールバックします。</p><h2 id="食べ放題・コース表示" tabindex="-1">食べ放題・コース表示 <a class="header-anchor" href="#食べ放題・コース表示" aria-label="Permalink to &quot;食べ放題・コース表示&quot;">​</a></h2><p>食べ放題プランでは、画面上部に残り時間、ラストオーダーまでの時間、1回あたりの注文可能数を表示します。コースでは、現在の提供位置と残り品目数を表示します。</p><h2 id="注文履歴とセルフ会計" tabindex="-1">注文履歴とセルフ会計 <a class="header-anchor" href="#注文履歴とセルフ会計" aria-label="Permalink to &quot;注文履歴とセルフ会計&quot;">​</a></h2><h3 id="注文履歴の二層表示" tabindex="-1">注文履歴の二層表示 <a class="header-anchor" href="#注文履歴の二層表示" aria-label="Permalink to &quot;注文履歴の二層表示&quot;">​</a></h3><p>注文履歴画面では、以下の2つのセクションに分かれて表示されます。</p><ul><li><strong>未払い注文</strong>: 今回の滞在でまだお会計が済んでいない注文です。</li><li><strong>会計済履歴</strong>: すでにお支払いが完了した過去の注文です。</li></ul><h3 id="ゲスト名-任意入力" tabindex="-1">ゲスト名（任意入力） <a class="header-anchor" href="#ゲスト名-任意入力" aria-label="Permalink to &quot;ゲスト名（任意入力）&quot;">​</a></h3><p>カートモーダルで、注文送信前に「ゲスト名」を入力できます。入力した名前は以下の場所で利用され、自分や同席者の注文を区別しやすくなります。</p><ul><li><strong>注文トラッカー</strong>: 誰が何を注文したかを確認。</li><li><strong>注文履歴</strong>: 過去の注文を名前で整理。</li><li><strong>セルフ会計画面</strong>: 支払うべき注文の確認。</li></ul><h3 id="個人負担目安-割り勘計算" tabindex="-1">個人負担目安（割り勘計算） <a class="header-anchor" href="#個人負担目安-割り勘計算" aria-label="Permalink to &quot;個人負担目安（割り勘計算）&quot;">​</a></h3><p>お会計前に、卓全体の合計金額をどのように分担するかを「手入力」でシミュレーションできる計算ツールです。以下の3つのモードから選べます。</p><ul><li><strong>均等に切り上げ</strong>: 合計金額を人数で割り、端数を切り上げた「一人あたりの支払額」を表示します。</li><li><strong>一人が端数を負担</strong>: 一人あたりの金額を指定し、残りの「端数を含めた金額」を特定の一人が支払う目安を表示します。</li><li><strong>自分の分 ＋ 残りを人数割り</strong>: 自分の支払額を手入力し、残りの金額を同席人数で割った目安を表示します。</li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>この計算機能は入力の手助けをするためのものであり、<code>guest_alias</code> と連動した自動計算や、品目を選んでの個別決済を行うものではありません。</p></div><div class="warning custom-block"><p class="custom-block-title">決済の制限事項</p><p>セルフ決済（Stripe Checkout）は、<strong>「テーブル全体の合計金額を一括で支払う」</strong> 仕組みです。特定の商品だけを選んで支払う「品目別の個別決済」には対応していません。厳密な個別会計が必要な場合は、店舗のレジスタッフへお申し付けください。</p></div><h3 id="会計後の継続注文" tabindex="-1">会計後の継続注文 <a class="header-anchor" href="#会計後の継続注文" aria-label="Permalink to &quot;会計後の継続注文&quot;">​</a></h3><p>セルフ決済が完了した後、画面に「続けて注文する」ボタンが表示されます。これを利用すると、同じテーブルセッションを維持したまま、追加の注文（デザートや飲み物など）をスムーズに行うことができます。</p><h2 id="aiウェイター" tabindex="-1">AIウェイター <a class="header-anchor" href="#aiウェイター" aria-label="Permalink to &quot;AIウェイター&quot;">​</a></h2><p>お客様はメニューについて質問できます。アレルギー、提供可否、価格など重要な内容は、店舗スタッフが最終確認してください。</p><h2 id="スタッフ呼び出し" tabindex="-1">スタッフ呼び出し <a class="header-anchor" href="#スタッフ呼び出し" aria-label="Permalink to &quot;スタッフ呼び出し&quot;">​</a></h2><p>お客様から呼び出しが入った場合は、店舗のルールに従って対応してください。呼び出し内容が分かる場合は、先に内容を確認してから向かうとスムーズです。</p><h2 id="困ったとき" tabindex="-1">困ったとき <a class="header-anchor" href="#困ったとき" aria-label="Permalink to &quot;困ったとき&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>対処</th></tr></thead><tbody><tr><td>メニューが表示されない</td><td>QRコード、店舗設定、メニュー公開状態を確認してください。</td></tr><tr><td>注文できない</td><td>Wi-Fi、売り切れ状態、テーブル開放状態を確認してください。</td></tr><tr><td>表示言語が違う</td><td>画面上の言語切替を確認してください。</td></tr><tr><td>金額が違う</td><td>商品価格、オプション、税区分を確認してください。</td></tr></tbody></table>',53)])])}const b=t(e,[["render",o]]);export{u as __pageData,b as default};
